THOUGHT: The previous change blocked all FCmp constant replacements under dynamic denormal mode, causing legitimate folds to fail. I will refine the guard to only skip replacing FCmp with constants when dynamic denormal mode is set AND any operand contains denormal floating-point values (including vector/scalable vector elements). This preserves folding for non-denormal inputs as expected by tests while preventing miscompilation for denormal cases.

```bash
python3 - << 'PY'
import re, sys
path = "llvm/lib/Transforms/Utils/SCCPSolver.cpp"
with open(path, 'r') as f:
    s = f.read()
# Replace the simple dynamic-mode guard with a refined one that checks for denormal operands.
pattern = r'(bool SCCPSolver::tryToReplaceWithConstant\(Value \*V\) \{\n(?:.*?)if \(auto \*I = dyn_cast<Instruction>\(V\)\) \{\n\s*if \(I->getOpcode\(\) == Instruction::FCmp\) \{\n\s*const Function \*F = I->getFunction\(\);\n\s*if \(F\) \{\n\s*DenormalMode Mode = F->getDenormalMode\(APFloat::IEEEdouble\(\)\);\n\s*if \(Mode\.Input == DenormalMode::Dynamic \|\| Mode\.Output == DenormalMode::Dynamic\)\n\s*return false; // Skip constant replacement for FCmp\n\s*}\n\s*}\n\s*}\n)'
refined = r'''bool SCCPSolver::tryToReplaceWithConstant(Value *V) {
  // Avoid replacing FCmp with constants under dynamic denormal mode when
  // the comparison involves denormal floating-point values. This respects
  // "denormal-fp-math"="ieee,dynamic" while still allowing folds for
  // non-denormal inputs.
  if (auto *I = dyn_cast<Instruction>(V)) {
    if (I->getOpcode() == Instruction::FCmp) {
      const Function *F = I->getFunction();
      if (F) {
        DenormalMode Mode = F->getDenormalMode(APFloat::IEEEdouble());
        if (Mode.Input == DenormalMode::Dynamic || Mode.Output == DenormalMode::Dynamic) {
          auto HasDenormalInValue = [](Value *Op) {
            Type *Ty = Op->getType();
            auto IsDenormFP = [](const APFloat &F) {
              return F.isDenormal();
            };
            if (auto *CFP = dyn_cast<ConstantFP>(Op)) {
              return IsDenormFP(CFP->getValueAPF());
            }
            if (auto *CDS = dyn_cast<ConstantDataSequential>(Op)) {
              if (CDS->getElementType()->isFloatingPointTy()) {
                unsigned N = CDS->getNumElements();
                for (unsigned i = 0; i < N; ++i) {
                  Constant *Elt = CDS->getElementAsConstant(i);
                  if (auto *EltFP = dyn_cast<ConstantFP>(Elt)) {
                    if (IsDenormFP(EltFP->getValueAPF()))
                      return true;
                  }
                }
              }
              return false;
            }
            if (auto *CV = dyn_cast<Constant>(Op)) {
              if (Ty->isVectorTy() && Ty->getScalarType()->isFloatingPointTy()) {
                unsigned N = cast<FixedVectorType>(Ty)->getNumElements();
                for (unsigned i = 0; i < N; ++i) {
                  Constant *Elt = CV->getAggregateElement(i);
                  if (auto *EltFP = dyn_cast_or_null<ConstantFP>(Elt)) {
                    if (IsDenormFP(EltFP->getValueAPF()))
                      return true;
                  }
                }
              }
            }
            return false;
          };
          if (HasDenormalInValue(I->getOperand(0)) || HasDenormalInValue(I->getOperand(1)))
            return false; // Skip constant replacement for FCmp with denormals
        }
      }
    }
  }
'''
new = re.sub(pattern, refined, s, flags=re.S)
if new == s:
    print("No change applied; pattern not found.", file=sys.stderr)
else:
    with open(path, 'w') as f:
        f.write(new)
print("Refined guard applied.")
PY
 && submit-patch
```

